import React, { useState } from 'react';
import axios from 'axios';

const KhaiBaoCoSo = () => {
  const [form, setForm] = useState({
    name: '',
    province: 'Tỉnh Đồng Tháp',
    district: '',
    ward: '',
    address: '',
    phone: '',
    lat: '',
    lng: ''
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await axios.post('http://localhost:4000/api/farms', form);
    alert('Đã lưu!');
  };

  return (
    <div className="p-4 w-full">
      <h1 className="text-2xl font-bold text-green-800 mb-4">Khai báo cơ sở nuôi</h1>
      <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">
        <input name="name" onChange={handleChange} placeholder="Tên cơ sở *" className="border p-2 rounded col-span-2" />
        <input name="district" onChange={handleChange} placeholder="Quận/Huyện *" className="border p-2 rounded" />
        <input name="ward" onChange={handleChange} placeholder="Phường/Xã *" className="border p-2 rounded" />
        <input name="address" onChange={handleChange} placeholder="Địa chỉ" className="border p-2 rounded col-span-2" />
        <input name="phone" onChange={handleChange} placeholder="Số điện thoại" className="border p-2 rounded col-span-2" />
        <input name="lat" onChange={handleChange} placeholder="Vĩ độ" className="border p-2 rounded" />
        <input name="lng" onChange={handleChange} placeholder="Kinh độ" className="border p-2 rounded" />
        <button type="submit" className="col-span-2 bg-green-600 text-white px-4 py-2 rounded">Lưu và nhập</button>
      </form>
    </div>
  );
};

export default KhaiBaoCoSo;
